member.example:
Bind the AudioSource time property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceTimeBinder _time;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _time;
    }


Bind the AudioSource time property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceTimeBinder Time =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _time;
    }

Switch the AudioSource time between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceTimeSwitcherBinder _isHighTime;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighTime;
    }


Switch the AudioSource time between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _highTime;
        
        [SerializeField] 
        private float _lowTime;
        
        private AudioSourceTimeSwitcherBinder IsHighTime => new(
            _audioSource, _highTime, _lowTime);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighTime;
    }
